## 6. 自动化生成脚本

### 生成CSS变量
```javascript
// 自动生成CSS变量文件
const designTokens = require('./design-tokens.json');

function generateCSSVariables(tokens) {
  let css = ':root {\n';

  // 生成颜色变量
  Object.entries(tokens.colors).forEach(([category, values]) => {
    Object.entries(values).forEach(([name, value]) => {
      if (typeof value === 'string') {
        css += `  --color-${category}-${name}: ${value};\n`;
      } else {
        Object.entries(value).forEach(([shade, shadeValue]) => {
          css += `  --color-${category}-${name}-${shade}: ${shadeValue};\n`;
        });
      }
    });
  });

  // 生成间距变量
  Object.entries(tokens.spacing).forEach(([size, value]) => {
    css += `  --spacing-${size}: ${value};\n`;
  });

  // 生成圆角变量
  Object.entries(tokens.borderRadius).forEach(([size, value]) => {
    css += `  --radius-${size}: ${value};\n`;
  });

  css += '}\n';
  return css;
}
```

