:root {
  /* 
   * 1.1 色彩系统 (Color System)
   * 基于主色#2D5BFF构建的完整色板
   */

  /* 主色 - 蓝色系 (专业、信任) */
  --color-primary-50: #E8F0FF;
  --color-primary-100: #C5D7FF;
  --color-primary-200: #9FBCFF;
  --color-primary-300: #7AA1FF;
  --color-primary-400: #5586FF;
  --color-primary-500: #2D5BFF;  /* 主色 */
  --color-primary-600: #1A4BD9;
  --color-primary-700: #0D3BB3;
  --color-primary-800: #052B8C;
  --color-primary-900: #001B66;

  /* 语义色 (Semantic Colors) */
  --color-success: #00C853;      /* 成功/已解决 */
  --color-warning: #FF6B35;      /* 警告/进行中 */
  --color-error: #FF3B30;        /* 错误/失败 */
  --color-info: #2D5BFF;         /* 信息/提示 */

  /* 中性色 (Neutral Colors) */
  --color-white: #FFFFFF;
  --color-gray-50: #F8F9FA;      /* 背景色 */
  --color-gray-100: #F0F0F0;     /* 边框/分割线 */
  --color-gray-200: #E0E0E0;     /* 禁用状态 */
  --color-gray-300: #CCCCCC;     /* 占位文字 */
  --color-gray-400: #999999;     /* 辅助文字 */
  --color-gray-500: #666666;     /* 次要文字 */
  --color-gray-600: #333333;     /* 主要文字 */
  --color-gray-700: #1A1A1A;     /* 标题文字 */
  --color-gray-800: #0D0D0D;     /* 深色模式文字 */
  --color-gray-900: #000000;     /* 纯黑 */

  /* 
   * 1.2 间距系统 (Spacing System)
   * 基于8px的网格系统，确保视觉一致性
   */
  --space-0: 0px;      /* 0px */
  --space-1: 4px;      /* 0.25rem */
  --space-2: 8px;      /* 0.5rem - 基础单位 */
  --space-3: 12px;     /* 0.75rem */
  --space-4: 16px;     /* 1rem */
  --space-5: 20px;     /* 1.25rem */
  --space-6: 24px;     /* 1.5rem */
  --space-8: 32px;     /* 2rem */
  --space-10: 40px;    /* 2.5rem */
  --space-12: 48px;    /* 3rem */
  --space-16: 64px;    /* 4rem */
  --space-20: 80px;    /* 5rem */

  /* 
   * 1.3 字体系统 (Typography System)
   * 使用系统字体确保最佳可读性
   */
  --font-family-sans: -apple-system, BlinkMacSystemFont, 'PingFang SC', 
                      'Hiragino Sans GB', 'Microsoft YaHei', sans-serif;
  --font-family-mono: 'SF Mono', Monaco, 'Cascadia Mono', 'Segoe UI Mono', 
                      'Roboto Mono', monospace;

  /* 字号 (Font Sizes) */
  --font-size-xs: 12px;    /* 辅助文字 */
  --font-size-sm: 14px;    /* 正文小字 */
  --font-size-base: 16px;  /* 正文标准 */
  --font-size-lg: 18px;    /* 小标题 */
  --font-size-xl: 20px;    /* 标题 */
  --font-size-2xl: 24px;   /* 大标题 */
  --font-size-3xl: 30px;   /* 超大标题 */
  --font-size-4xl: 36px;   /* 展示标题 */

  /* 字重 (Font Weights) */
  --font-weight-regular: 400;   /* 常规 */
  --font-weight-medium: 500;    /* 中等 */
  --font-weight-semibold: 600;  /* 半粗 */
  --font-weight-bold: 700;      /* 粗体 */

  /* 行高 (Line Heights) */
  --line-height-tight: 1.2;     /* 紧凑 */
  --line-height-normal: 1.5;    /* 标准 */
  --line-height-relaxed: 1.8;   /* 宽松 */

  /* 
   * 1.4 圆角系统 (Border Radius)
   * 一致的圆角设计，增强友好感
   */
  --radius-none: 0px;
