  --radius-base: 8px;   /* 按钮 */
  --radius-md: 12px;    /* 卡片 */
  --radius-lg: 16px;    /* 大卡片 */
  --radius-xl: 20px;    /* 模态框 */
  --radius-2xl: 24px;   /* 超大元素 */
  --radius-full: 9999px; /* 圆形 */

